import{_ as t,c as o,o as r,a1 as a}from"./chunks/framework.DDNAyvCW.js";const d="/assets/llms.DYkpxowe.png",u=JSON.parse('{"title":"Model List","description":"","frontmatter":{},"headers":[],"relativePath":"docs/ai/llms/index.md","filePath":"docs/ai/llms/index.md"}'),s={name:"docs/ai/llms/index.md"};function n(i,e,l,c,p,h){return r(),o("div",null,e[0]||(e[0]=[a('<h1 id="model-list" tabindex="-1">Model List <a class="header-anchor" href="#model-list" aria-label="Permalink to &quot;Model List&quot;">​</a></h1><p>Chaterm supports multiple AI model providers out of the box, and you can add your own for maximum flexibility.</p><p><img src="'+d+'" alt=""></p><h2 id="built-in-models" tabindex="-1">Built-in Models <a class="header-anchor" href="#built-in-models" aria-label="Permalink to &quot;Built-in Models&quot;">​</a></h2><p>Chaterm ships with several high-quality models pre-configured and ready to use — no setup required. Simply select one from the model dropdown in any AI dialog.</p><h2 id="getting-started-with-your-first-custom-model" tabindex="-1">Getting Started with Your First Custom Model <a class="header-anchor" href="#getting-started-with-your-first-custom-model" aria-label="Permalink to &quot;Getting Started with Your First Custom Model&quot;">​</a></h2><p>Follow these steps to add a custom model provider. The example below uses OpenAI, but the process is similar for all providers.</p><ol><li>Open <strong>Settings</strong> by clicking the gear icon in the top-right corner.</li><li>Navigate to the <strong>&quot;Models&quot;</strong> tab in the left menu.</li><li>Click <strong>&quot;Add Model&quot;</strong>.</li><li>Select <strong>OpenAI</strong> (or your preferred provider) from the provider list.</li><li>Enter the <strong>API endpoint URL</strong> (e.g., <code>https://api.openai.com/v1</code>).</li><li>Paste your <strong>API key</strong>.</li><li>Type or select a <strong>model name</strong> (e.g., <code>gpt-5</code>).</li><li>Click <strong>&quot;Test Connection&quot;</strong> — a success message confirms everything is working.</li><li>Click <strong>&quot;Save&quot;</strong> — the model now appears in your model dropdown across all AI dialogs.</li></ol><div class="tip custom-block"><p class="custom-block-title">Recommended first setup</p><p>If you are new to Chaterm&#39;s AI features, start with <strong>DeepSeek</strong> or <strong>OpenAI</strong>. Both require only an API key, have straightforward setup, and provide strong general-purpose models suitable for command generation and agent tasks.</p></div><hr><h2 id="provider-reference" tabindex="-1">Provider Reference <a class="header-anchor" href="#provider-reference" aria-label="Permalink to &quot;Provider Reference&quot;">​</a></h2><h3 id="_1-litellm" tabindex="-1">1. LiteLLM <a class="header-anchor" href="#_1-litellm" aria-label="Permalink to &quot;1. LiteLLM&quot;">​</a></h3><p>Connect to multiple model providers through a unified LiteLLM gateway.</p><table tabindex="0"><thead><tr><th>Configuration Item</th><th>Description</th><th>Required</th></tr></thead><tbody><tr><td><strong>URL Address</strong></td><td>LiteLLM service endpoint</td><td>Yes</td></tr><tr><td><strong>API Key</strong></td><td>Access key for the LiteLLM gateway</td><td>Yes</td></tr><tr><td><strong>Model Name</strong></td><td>Model identifier (e.g., <code>gpt-5</code>, <code>claude-sonnet-4-6</code>)</td><td>Yes</td></tr></tbody></table><p><strong>Best for:</strong> Teams that already run a LiteLLM proxy to unify access to multiple providers behind a single endpoint.</p><hr><h3 id="_2-openai" tabindex="-1">2. OpenAI <a class="header-anchor" href="#_2-openai" aria-label="Permalink to &quot;2. OpenAI&quot;">​</a></h3><p>Connect directly to OpenAI or any OpenAI-compatible API.</p><table tabindex="0"><thead><tr><th>Configuration Item</th><th>Description</th><th>Required</th></tr></thead><tbody><tr><td><strong>OpenAI URL Address</strong></td><td>API endpoint (default: <code>https://api.openai.com/v1</code>)</td><td>Yes</td></tr><tr><td><strong>OpenAI API Key</strong></td><td>Your OpenAI API key</td><td>Yes</td></tr><tr><td><strong>Model Name</strong></td><td>Model to use (e.g., <code>gpt-5</code>, <code>claude-sonnet-4-6</code>, <code>claude-opus-4-5</code>)</td><td>Yes</td></tr></tbody></table><p><strong>Best for:</strong> Direct access to OpenAI models, or connecting to third-party services that expose an OpenAI-compatible API.</p><hr><h3 id="_3-amazon-bedrock" tabindex="-1">3. Amazon Bedrock <a class="header-anchor" href="#_3-amazon-bedrock" aria-label="Permalink to &quot;3. Amazon Bedrock&quot;">​</a></h3><p>Use AWS Bedrock for enterprise-grade AI with AWS security and compliance.</p><table tabindex="0"><thead><tr><th>Configuration Item</th><th>Description</th><th>Required</th></tr></thead><tbody><tr><td><strong>AWS Access Key</strong></td><td>IAM access key ID</td><td>Yes</td></tr><tr><td><strong>AWS Secret Key</strong></td><td>IAM secret access key</td><td>Yes</td></tr><tr><td><strong>AWS Session Token</strong></td><td>Temporary session token (for assumed roles)</td><td>No</td></tr><tr><td><strong>AWS Region</strong></td><td>Service region (e.g., <code>us-east-1</code>)</td><td>Yes</td></tr><tr><td><strong>Custom VPC Endpoint</strong></td><td>Private endpoint for VPC-based access</td><td>No</td></tr><tr><td><strong>Cross-Region Inference</strong></td><td>Enable inference across multiple regions</td><td>No</td></tr><tr><td><strong>Model Name</strong></td><td>Bedrock model identifier</td><td>Yes</td></tr></tbody></table><p><strong>Best for:</strong> Organizations already invested in AWS that need enterprise security, compliance controls, and private network access.</p><hr><h3 id="_4-deepseek" tabindex="-1">4. DeepSeek <a class="header-anchor" href="#_4-deepseek" aria-label="Permalink to &quot;4. DeepSeek&quot;">​</a></h3><p>Connect to the DeepSeek API for strong reasoning and coding capabilities.</p><table tabindex="0"><thead><tr><th>Configuration Item</th><th>Description</th><th>Required</th></tr></thead><tbody><tr><td><strong>DeepSeek API Key</strong></td><td>Your DeepSeek API key</td><td>Yes</td></tr><tr><td><strong>Model Name</strong></td><td>Model to use (e.g., <code>deepseek-chat</code>, <code>deepseek-reasoner</code>)</td><td>Yes</td></tr></tbody></table><p><strong>Best for:</strong> Cost-effective access to models with strong reasoning and code generation capabilities.</p><hr><h3 id="_5-ollama-local-deployment" tabindex="-1">5. Ollama (Local Deployment) <a class="header-anchor" href="#_5-ollama-local-deployment" aria-label="Permalink to &quot;5. Ollama (Local Deployment)&quot;">​</a></h3><p>Run models locally for maximum privacy and offline access.</p><table tabindex="0"><thead><tr><th>Configuration Item</th><th>Description</th><th>Required</th></tr></thead><tbody><tr><td><strong>Ollama URL Address</strong></td><td>Local service address (default: <code>http://localhost:11434</code>)</td><td>Yes</td></tr><tr><td><strong>Model Name</strong></td><td>Locally installed model (e.g., <code>llama3</code>, <code>codellama</code>, <code>mistral</code>)</td><td>Yes</td></tr></tbody></table><p><strong>Best for:</strong> Air-gapped environments, data-sensitive workloads, or experimentation without API costs.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Make sure the Ollama service is running before testing the connection. You can start it with <code>ollama serve</code> and pull models with <code>ollama pull &lt;model-name&gt;</code>.</p></div><hr><h2 id="configuration-tips" tabindex="-1">Configuration Tips <a class="header-anchor" href="#configuration-tips" aria-label="Permalink to &quot;Configuration Tips&quot;">​</a></h2><ul><li><strong>Test after every change</strong> — Always click &quot;Test Connection&quot; after modifying any provider configuration.</li><li><strong>Multiple models</strong> — You can configure several providers and models simultaneously, then switch between them per dialog.</li><li><strong>API key security</strong> — Chaterm stores credentials locally. Rotate keys periodically with your provider.</li><li><strong>Performance</strong> — Monitor response times. Local models (Ollama) have no network latency but depend on your hardware. Cloud models are faster on powerful servers but add network round-trip time.</li></ul><hr><h2 id="related-documentation" tabindex="-1">Related Documentation <a class="header-anchor" href="#related-documentation" aria-label="Permalink to &quot;Related Documentation&quot;">​</a></h2><ul><li><a href="/docs/ai/settings/">AI Settings</a> — Create dialogs and configure providers step by step</li><li><a href="/docs/ai/preferences/">AI Preferences</a> — Adjust reasoning depth, auto-execution, and security policies</li></ul>',42)]))}const m=t(s,[["render",n]]);export{u as __pageData,m as default};
